import React, { useState, useRef, useEffect } from 'react';
import { Upload, File, X, CheckCircle, FileText, AlertCircle } from 'lucide-react';

const DocumentUpload = () => {
  const [formData, setFormData] = useState({
    employeeName: '',
    employeeId: '',
    store: '',
    documentType: '',
    issueDate: '',
    expiryDate: '',
    remarks: ''
  });
  const [accumulatedFiles, setAccumulatedFiles] = useState([]);
  const [tempFiles, setTempFiles] = useState([]);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [dragActive, setDragActive] = useState(false);
  const [employees] = useState([
    { id: 'EMP001', name: 'John Doe', store: 'Store 1' },
    { id: 'EMP002', name: 'Priya Singh', store: 'Store 2' },
    { id: 'EMP003', name: 'Mike Johnson', store: 'Store 3' }
  ]);
  const [documentTypes] = useState([
    'ID Proof',
    'Driving License',
    'Medical Certificate',
    'Training Certificate',
    'Employment Contract',
    'Educational Certificate'
  ]);
  const [uploadResults, setUploadResults] = useState([]);
  const [showResults, setShowResults] = useState(false);
  const [errors, setErrors] = useState({});
  const fileInputRef = useRef(null);

  const stores = ['Store 1', 'Store 2', 'Store 3', 'Store 4', 'Store 5'];

  useEffect(() => {
    const today = new Date().toISOString().split('T')[0];
    setFormData(prev => ({ ...prev, issueDate: today }));
  }, []);

  const getTodayDate = () => new Date().toISOString().split('T')[0];

  const getMinExpiryDate = () => {
    if (!formData.issueDate) {
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      return tomorrow.toISOString().split('T')[0];
    }
    const issueDate = new Date(formData.issueDate);
    issueDate.setDate(issueDate.getDate() + 1);
    return issueDate.toISOString().split('T')[0];
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
    
    if (name === 'employeeName' && value) {
      const selectedEmployee = employees.find(emp => emp.name === value);
      if (selectedEmployee) {
        setFormData(prev => ({
          ...prev,
          employeeName: value,
          employeeId: selectedEmployee.id,
          store: selectedEmployee.store || prev.store
        }));
        return;
      }
    }

    if (name === 'documentType') {
      const today = getTodayDate();
      setFormData(prev => ({
        ...prev,
        documentType: value,
        issueDate: today,
        expiryDate: ''
      }));
      return;
    }
    
    if (name === 'issueDate') {
      setFormData(prev => {
        const newFormData = { ...prev, issueDate: value };
        if (prev.expiryDate && value) {
          const issueDate = new Date(value);
          const expiryDate = new Date(prev.expiryDate);
          if (expiryDate <= issueDate) {
            newFormData.expiryDate = '';
          }
        }
        return newFormData;
      });
      return;
    }
    
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFileSelect(e.dataTransfer.files);
    }
  };

  const handleFileSelect = (selectedFiles) => {
    if (!formData.documentType) {
      alert('Please select document type first');
      return;
    }
    if (!formData.issueDate || !formData.expiryDate) {
      alert('Please fill issue date and expiry date first');
      return;
    }

    const fileArray = Array.from(selectedFiles);
    const validTypes = ['application/pdf', 'image/jpeg', 'image/png', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
    
    const validFiles = fileArray.filter(file => {
      if (validTypes.includes(file.type)) return true;
      alert(`Invalid file type: ${file.name}`);
      return false;
    });
    
    setTempFiles(prev => [...prev, ...validFiles]);
  };

  const handleFileInput = (e) => {
    if (e.target.files && e.target.files.length > 0) {
      handleFileSelect(e.target.files);
      e.target.value = '';
    }
  };

  const removeTempFile = (index) => {
    setTempFiles(prev => prev.filter((_, i) => i !== index));
  };

  const removeAccumulatedFile = (index) => {
    setAccumulatedFiles(prev => prev.filter((_, i) => i !== index));
  };

  const addFilesToAccumulated = () => {
    if (tempFiles.length === 0) {
      alert('No files to add');
      return;
    }

    const filesWithMetadata = tempFiles.map(file => ({
      file: file,
      documentType: formData.documentType,
      issueDate: formData.issueDate,
      expiryDate: formData.expiryDate
    }));

    setAccumulatedFiles(prev => [...prev, ...filesWithMetadata]);
    setTempFiles([]);
    
    const today = getTodayDate();
    setFormData(prev => ({
      ...prev,
      documentType: '',
      issueDate: today,
      expiryDate: ''
    }));
  };

  const validateForm = () => {
    const newErrors = {};
    if (!formData.employeeName) newErrors.employeeName = 'Please select an employee';
    if (!formData.employeeId) newErrors.employeeId = 'Employee ID is required';
    if (!formData.store) newErrors.store = 'Please select a store';
    if (accumulatedFiles.length === 0) newErrors.files = 'Please add at least one file to upload';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    setIsUploading(true);
    setUploadProgress(0);
    setShowResults(false);

    const results = [];
    for (let i = 0; i < accumulatedFiles.length; i++) {
      await new Promise(resolve => setTimeout(resolve, 500));
      results.push({
        fileName: accumulatedFiles[i].file.name,
        documentType: accumulatedFiles[i].documentType,
        success: true,
        message: 'Uploaded successfully'
      });
      setUploadProgress(Math.round(((i + 1) / accumulatedFiles.length) * 100));
    }

    setUploadResults(results);
    setShowResults(true);
    setIsUploading(false);
    
    const today = getTodayDate();
    setFormData({
      employeeId: '',
      employeeName: '',
      store: '',
      documentType: '',
      issueDate: today,
      expiryDate: '',
      remarks: ''
    });
    setAccumulatedFiles([]);
    setTempFiles([]);
    setUploadProgress(0);
  };

  const formatFileSize = (bytes) => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(2) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(2) + ' MB';
  };

  return (
    <div className="p-4 bg-gray-50 min-h-screen">
      <div className="max-w-6xl mx-auto bg-white rounded-2xl shadow-lg overflow-hidden">
        {/* Sticky Header */}
        <div 
          className="bg-gradient-to-r from-indigo-600 to-purple-600 text-white p-6 sticky top-0 z-50"
          style={{ boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)' }}
        >
          <h3 className="text-2xl font-bold flex items-center gap-2 m-0">
            <Upload size={28} />
            Upload Employee Documents
          </h3>
        </div>

        <div className="p-6">
          {/* Upload Results */}
          {showResults && uploadResults.length > 0 && (
            <div className={`mb-6 p-4 rounded-lg border-l-4 ${uploadResults.every(r => r.success) ? 'bg-green-50 border-green-500' : 'bg-yellow-50 border-yellow-500'}`}>
              <div className="flex justify-between items-center mb-2">
                <div className="font-bold flex items-center gap-2">
                  <CheckCircle size={20} className={uploadResults.every(r => r.success) ? 'text-green-600' : 'text-yellow-600'} />
                  Upload Results: {uploadResults.filter(r => r.success).length} succeeded, {uploadResults.filter(r => !r.success).length} failed
                </div>
                <button 
                  onClick={() => setShowResults(false)}
                  className="text-gray-500 hover:text-gray-700"
                >
                  <X size={20} />
                </button>
              </div>
              <ul className="ml-6 space-y-1">
                {uploadResults.map((result, index) => (
                  <li key={index} className="text-sm">
                    <CheckCircle size={14} className={`inline mr-1 ${result.success ? 'text-green-600' : 'text-red-600'}`} />
                    <strong>{result.documentType}</strong> - {result.fileName}: {result.message}
                  </li>
                ))}
              </ul>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            {/* Employee */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Employee <span className="text-red-500">*</span>
              </label>
              <select
                name="employeeName"
                value={formData.employeeName}
                onChange={handleInputChange}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              >
                <option value="">Select Employee</option>
                {employees.map(emp => (
                  <option key={emp.id} value={emp.name}>
                    {emp.name} - {emp.id} ({emp.store})
                  </option>
                ))}
              </select>
              {errors.employeeName && <p className="text-red-500 text-sm mt-1">{errors.employeeName}</p>}
            </div>

            {/* Employee ID */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Employee ID <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                name="employeeId"
                value={formData.employeeId}
                placeholder="Auto-filled"
                readOnly
                className="w-full px-4 py-2 bg-gray-100 border border-gray-300 rounded-lg"
              />
            </div>

            {/* Store */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Store <span className="text-red-500">*</span>
              </label>
              <select
                name="store"
                value={formData.store}
                onChange={handleInputChange}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              >
                <option value="">Select Store</option>
                {stores.map(store => (
                  <option key={store} value={store}>{store}</option>
                ))}
              </select>
              {errors.store && <p className="text-red-500 text-sm mt-1">{errors.store}</p>}
            </div>

            {/* Document Type */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Document Type <span className="text-red-500">*</span>
              </label>
              <select
                name="documentType"
                value={formData.documentType}
                onChange={handleInputChange}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              >
                <option value="">Select Document Type</option>
                {documentTypes.map(type => (
                  <option key={type} value={type}>{type}</option>
                ))}
              </select>
              <p className="text-gray-500 text-xs mt-1">Change type to add different document types</p>
            </div>

            {/* Issue Date */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Issue Date <span className="text-red-500">*</span>
              </label>
              <input
                type="date"
                name="issueDate"
                value={formData.issueDate}
                onChange={handleInputChange}
                max={getTodayDate()}
                disabled={!formData.documentType}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent disabled:bg-gray-100"
              />
            </div>

            {/* Expiry Date */}
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Expiry Date <span className="text-red-500">*</span>
              </label>
              <input
                type="date"
                name="expiryDate"
                value={formData.expiryDate}
                onChange={handleInputChange}
                min={getMinExpiryDate()}
                disabled={!formData.issueDate}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent disabled:bg-gray-100"
              />
            </div>
          </div>

          {/* Remarks */}
          <div className="mb-4">
            <label className="block text-sm font-semibold text-gray-700 mb-2">Remarks</label>
            <textarea
              name="remarks"
              value={formData.remarks}
              onChange={handleInputChange}
              rows={2}
              placeholder="Enter remarks (optional)"
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
            />
          </div>

          {/* Upload Area */}
          <div className="mb-4">
            <label className="block text-sm font-semibold text-gray-700 mb-2">
              Upload Document(s) <span className="text-red-500">*</span>
              {tempFiles.length > 0 && (
                <span className="ml-2 px-3 py-1 bg-indigo-100 text-indigo-700 rounded-full text-xs font-semibold">
                  {tempFiles.length} file(s) selected
                </span>
              )}
            </label>
            <div
              className={`border-2 border-dashed rounded-xl p-4 cursor-pointer transition-all ${
                dragActive ? 'border-purple-500 bg-purple-50' : 
                tempFiles.length > 0 ? 'border-gray-300 bg-white' : 
                'border-gray-300 bg-gray-50 hover:border-indigo-400 hover:bg-indigo-50'
              }`}
              onDragEnter={handleDrag}
              onDragLeave={handleDrag}
              onDragOver={handleDrag}
              onDrop={handleDrop}
              onClick={() => fileInputRef.current?.click()}
            >
              <input
                ref={fileInputRef}
                type="file"
                onChange={handleFileInput}
                accept=".pdf,.docx,.jpg,.jpeg,.png"
                multiple
                className="hidden"
              />
              {tempFiles.length > 0 ? (
                <div className="space-y-2">
                  {tempFiles.map((file, index) => (
                    <div 
                      key={index} 
                      className="flex items-center gap-2 bg-gray-100 border border-gray-200 rounded-lg p-2"
                    >
                      <File size={16} className="text-indigo-600 flex-shrink-0" />
                      <span className="flex-1 text-sm font-medium truncate">{file.name}</span>
                      <span className="text-xs text-gray-500 flex-shrink-0">({formatFileSize(file.size)})</span>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          removeTempFile(index);
                        }}
                        className="text-red-500 hover:text-red-700 flex-shrink-0"
                      >
                        <X size={16} />
                      </button>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-8">
                  <Upload size={40} className="mx-auto text-gray-400 mb-2" />
                  <p className="text-gray-600 mb-1">Click or drag files here</p>
                  <p className="text-gray-400 text-xs">PDF, DOCX, JPG, PNG (Max 10MB)</p>
                </div>
              )}
            </div>
            {errors.files && <p className="text-red-500 text-sm mt-1">{errors.files}</p>}
          </div>

          {/* Add Files Button */}
          {tempFiles.length > 0 && (
            <div className="mb-4">
              <button
                onClick={addFilesToAccumulated}
                disabled={!formData.documentType || !formData.issueDate || !formData.expiryDate}
                className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center gap-2 transition-all"
              >
                <FileText size={16} />
                Add These Files ({formData.documentType || 'Select Type'})
              </button>
              <p className="text-gray-500 text-xs mt-1">Add files, then change document type to add more</p>
            </div>
          )}

          {/* Accumulated Files */}
          {accumulatedFiles.length > 0 && (
            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Files to Upload ({accumulatedFiles.length})
              </label>
              <div className="max-h-80 overflow-y-auto space-y-2 border border-gray-200 rounded-lg p-2">
                {accumulatedFiles.map((fileObj, index) => (
                  <div 
                    key={index} 
                    className="flex items-start gap-3 bg-white border-l-4 border-indigo-500 p-3 rounded-lg shadow-sm hover:shadow-md transition-shadow"
                  >
                    <FileText size={20} className="text-indigo-600 flex-shrink-0 mt-1" />
                    <div className="flex-1 min-w-0">
                      <div className="font-bold text-gray-800">{fileObj.documentType}</div>
                      <div className="text-sm text-gray-600 truncate">
                        {fileObj.file.name} ({formatFileSize(fileObj.file.size)})
                      </div>
                      <div className="text-xs text-gray-500 mt-1">
                        Issue: {fileObj.issueDate} | Expiry: {fileObj.expiryDate}
                      </div>
                    </div>
                    <button
                      onClick={() => removeAccumulatedFile(index)}
                      className="text-red-500 hover:text-red-700 flex-shrink-0"
                    >
                      <X size={20} />
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Upload Progress */}
          {isUploading && (
            <div className="mb-6">
              <div className="flex justify-between mb-2 text-sm text-gray-700">
                <span>Uploading {accumulatedFiles.length} file(s)...</span>
                <span>{uploadProgress}%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-6 overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-indigo-600 to-purple-600 transition-all duration-300 flex items-center justify-center text-white text-xs font-semibold"
                  style={{ width: `${uploadProgress}%` }}
                >
                  {uploadProgress}%
                </div>
              </div>
            </div>
          )}

          {/* Submit Button */}
          <button
            onClick={handleSubmit}
            disabled={isUploading || accumulatedFiles.length === 0}
            className="w-full py-4 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-xl font-bold text-lg shadow-lg hover:shadow-xl disabled:from-gray-400 disabled:to-gray-500 disabled:cursor-not-allowed transition-all"
          >
            {isUploading ? 'Uploading...' : 'Upload Documents'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default DocumentUpload;
